// Ensure input exists
let text = String($json.output || "I'm sorry, I couldn't process that request.");

// 1. Check for raw Tool/JSON dumps (Safety Fallback)
if (text.includes('{"') || text.includes('Used tools:')) {
  return [{ json: { output: "<b>Search result too large.</b> Please be more specific with the company name." } }];
}

// 2. Escape HTML special characters (to prevent Telegram 400 errors)
text = text.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

// 3. Re-convert specific Markdown back to Telegram-safe HTML
text = text
  .replace(/&lt;b&gt;(.*?)&lt;\/b&gt;/g, '<b>$1</b>') // Handle pre-existing bold
  .replace(/\*\*(.*?)\*\*/g, '<b>$1</b>')           // **Bold** -> <b>
  .replace(/^\d+\.\s+/gm, '• ')                     // Numbered lists -> Bullets
  .replace(/^-+\s+/gm, '• ')                        // Dash lists -> Bullets
  .replace(/^#+\s*/gm, '');                         // Remove headers

return [{ json: { output: text.trim() } }];
